// @ts-nocheck

function firstNonEmpty() {
  for (let i = 0; i < arguments.length; i++) {
    const value = arguments[i];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function onlyDigits(value) {
  return String(value || '').replace(/\D/g, '');
}

function getByPath(obj, path) {
  try {
    return path.split('.').reduce((cur, p) => {
      if (cur === undefined || cur === null) return '';
      return cur[p];
    }, obj) ?? '';
  } catch (e) {
    return '';
  }
}

function normalizeBrazilWhatsappPhone(value) {
  let raw = String(value || '');
  let digits = onlyDigits(raw.split('@')[0]);

  if (!digits) return '';

  digits = digits.replace(/^0+/, '');

  // Se veio sem DDI, assume Brasil.
  if (!digits.startsWith('55')) {
    if (digits.length === 10 || digits.length === 11) {
      digits = '55' + digits;
    }
  }

  // Regra validada:
  // 554588230845@s.whatsapp.net -> 5545988230845
  // 55 + DDD + 8 dígitos iniciando em 6/7/8/9 -> inserir nono dígito.
  if (digits.startsWith('55') && digits.length === 12) {
    const ddd = digits.slice(2, 4);
    const subscriber = digits.slice(4);

    if (/^[6-9]/.test(subscriber)) {
      digits = '55' + ddd + '9' + subscriber;
    }
  }

  return digits;
}

function getMessageText(message) {
  if (!message || typeof message !== 'object') return '';

  const orderCount = getByPath(message, 'orderMessage.itemCount');
  const orderFallback = orderCount ? 'Pedido/carrinho com ' + orderCount + ' itens' : '';

  return firstNonEmpty(
    getByPath(message, 'conversation'),
    getByPath(message, 'extendedTextMessage.text'),
    getByPath(message, 'imageMessage.caption'),
    getByPath(message, 'videoMessage.caption'),
    getByPath(message, 'documentMessage.caption'),
    getByPath(message, 'buttonsResponseMessage.selectedDisplayText'),
    getByPath(message, 'buttonsResponseMessage.selectedButtonId'),
    getByPath(message, 'listResponseMessage.title'),
    getByPath(message, 'listResponseMessage.singleSelectReply.selectedRowId'),
    getByPath(message, 'templateButtonReplyMessage.selectedDisplayText'),
    getByPath(message, 'templateButtonReplyMessage.selectedId'),
    getByPath(message, 'orderMessage.orderTitle'),
    orderFallback
  );
}

function detectMessageType(data, message) {
  const declared = firstNonEmpty(
    getByPath(data, 'messageType'),
    getByPath(data, 'type')
  );

  if (declared) {
    const d = String(declared).toLowerCase();

    if (d.includes('image')) return 'image';
    if (d.includes('audio')) return 'audio';
    if (d.includes('video')) return 'video';
    if (d.includes('document')) return 'document';
    if (d.includes('order')) return 'cart';
    if (d.includes('cart')) return 'cart';
    if (d.includes('location')) return 'location';
    if (d.includes('contact')) return 'contact';
    if (d.includes('conversation') || d.includes('text')) return 'text';
  }

  if (!message || typeof message !== 'object') return 'unknown';

  if (message.conversation || message.extendedTextMessage) return 'text';
  if (message.imageMessage) return 'image';
  if (message.audioMessage || message.pttMessage) return 'audio';
  if (message.videoMessage) return 'video';
  if (message.documentMessage) return 'document';
  if (message.orderMessage) return 'cart';
  if (message.locationMessage) return 'location';
  if (message.contactMessage || message.contactsArrayMessage) return 'contact';

  return 'unknown';
}

function toIsoTimestamp(value) {
  if (!value) return new Date().toISOString();

  if (typeof value === 'number') {
    if (value < 10000000000) {
      return new Date(value * 1000).toISOString();
    }

    return new Date(value).toISOString();
  }

  const parsed = new Date(value);
  if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();

  return new Date().toISOString();
}

// Ponto principal da correção:
// o Webhook do n8n entrega a Evolution dentro de $json.body.
const envelope = $json || {};
const payload = envelope.body || envelope;

const data =
  payload.data ||
  payload.message ||
  (payload.messages && payload.messages[0]) ||
  payload;

const key = data.key || payload.key || {};
const message = data.message || payload.message || {};

const remoteJid = firstNonEmpty(
  key.remoteJid,
  key.remoteJidAlt,
  data.remoteJid,
  data.from,
  data.chatId,
  payload.remoteJid,
  payload.from,
  payload.chatId,
  data.sender,
  payload.sender
);

const fromMe = Boolean(
  key.fromMe !== undefined ? key.fromMe :
  data.fromMe !== undefined ? data.fromMe :
  payload.fromMe !== undefined ? payload.fromMe :
  false
);

const messageText = String(
  firstNonEmpty(
    getMessageText(message),
    data.text,
    payload.text,
    data.body,
    payload.body
  )
).trim();

const messageType = detectMessageType(data, message);

const pushName = String(firstNonEmpty(
  data.pushName,
  data.senderName,
  payload.pushName,
  payload.senderName,
  data.notifyName,
  'Cliente WhatsApp'
)).trim();

const phoneNormalized = normalizeBrazilWhatsappPhone(remoteJid);

const messageId = firstNonEmpty(
  key.id,
  data.id,
  payload.id,
  data.messageId,
  payload.messageId
);

const instance = firstNonEmpty(
  payload.instance,
  data.instance,
  payload.instanceName,
  data.instanceName,
  'julia'
);

const event = firstNonEmpty(
  payload.event,
  data.event,
  ''
);

let mediaUrl = '';
let mediaKey = null;

if (message.audioMessage || message.pttMessage) {
  const audioMsg = message.audioMessage || message.pttMessage;
  mediaUrl = firstNonEmpty(audioMsg.url, audioMsg.directPath);
  mediaKey = key;
}

if (message.imageMessage) {
  mediaUrl = firstNonEmpty(message.imageMessage.url, message.imageMessage.directPath);
  mediaKey = key;
}

if (message.videoMessage) {
  mediaUrl = firstNonEmpty(message.videoMessage.url, message.videoMessage.directPath);
  mediaKey = key;
}

if (message.documentMessage) {
  mediaUrl = firstNonEmpty(message.documentMessage.url, message.documentMessage.directPath);
  mediaKey = key;
}

let skip = false;
let reason = '';

if (fromMe) {
  skip = true;
  reason = 'fromMe';
}

if (String(remoteJid || '').includes('@g.us')) {
  skip = true;
  reason = 'group';
}

if (String(remoteJid || '').includes('status@broadcast')) {
  skip = true;
  reason = 'status';
}

if (!phoneNormalized) {
  skip = true;
  reason = reason || 'phone_not_found';
}

const textNorm = messageText
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const rawPayload = {
  event,
  instance,
  key,
  pushName,
  message_type: messageType,
  messageTimestamp: firstNonEmpty(
    data.messageTimestamp,
    payload.messageTimestamp,
    data.timestamp,
    payload.timestamp
  )
};

return [{
  json: {
    phone_normalized: phoneNormalized,
    push_name: pushName,
    instance,
    message_id: messageId,
    message_type: messageType,
    message_text: messageText,
    message_text_normalized: textNorm,
    message_timestamp: toIsoTimestamp(firstNonEmpty(
      data.messageTimestamp,
      payload.messageTimestamp,
      data.timestamp,
      payload.timestamp
    )),
    media_url: mediaUrl,
    media_key_json: mediaKey || null,
    raw_payload: rawPayload,
    full_payload: payload,
    remote_jid: remoteJid,
    external_contact_id: remoteJid,
    channel: 'whatsapp',
    from_me: fromMe,
    event,
    skip
  }
}];

// @ts-nocheck
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').item.json;
const bufRaw = $json.value || $json.propertyName || '';

let existing = [];
try {
  if (bufRaw && typeof bufRaw === 'string' && bufRaw.startsWith('[')) {
    existing = JSON.parse(bufRaw) || [];
  }
} catch (_) {}

const newMsg = {
  message_id: norm.message_id,
  message_text: norm.message_text || '',
  message_type: norm.message_type || 'text',
  media_url: norm.media_url || '',
  ts: Date.now()
};

existing.push(newMsg);

// Keep last 10 messages max
if (existing.length > 10) existing = existing.slice(-10);

return [{ json: { ...norm, buffer: existing, buffer_json: JSON.stringify(existing) } }];

// @ts-nocheck
// Monta contexto final a partir do buffer acumulado
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').item.json;
let buffer = [];
try {
const raw = $json.value || $json.propertyName || '';
  if (raw && typeof raw === 'string' && raw.startsWith('[')) {
    buffer = JSON.parse(raw) || [];
  }
} catch (_) {}

if (buffer.length === 0) {
  buffer = [{
    message_id: norm.message_id || '',
    message_text: norm.message_text || '',
    message_type: norm.message_type || 'text',
    media_url: norm.media_url || '',
    ts: Date.now()
  }];
}

// Merge text messages
const mergedText = buffer
  .map(m => (m.message_text || '').trim())
  .filter(Boolean)
  .join('\n');

const mergedTextNorm = mergedText.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();

// Detect special types in buffer (priority: cart > audio > image > text)
const hasCart = buffer.some(m => m.message_type === 'cart');
const hasAudio = buffer.some(m => m.message_type === 'audio');
const hasImage = buffer.some(m => m.message_type === 'image');

let effectiveType = 'text';
if (hasCart) effectiveType = 'cart';
else if (hasAudio) effectiveType = 'audio';
else if (hasImage) effectiveType = 'image';
else if (buffer.length === 1) effectiveType = norm.message_type;

// Get media URL/key from the relevant buffer message
const mediaMsg = buffer.find(m => ['audio', 'image', 'video'].includes(m.message_type));
const mediaUrl = mediaMsg?.media_url || norm.media_url || '';

return [{
  json: {
    ...norm,
    message_text: mergedText || norm.message_text || '',
    message_text_normalized: mergedTextNorm || norm.message_text_normalized || '',
    message_type: effectiveType,
    buffer_count: buffer.length,
    buffer_messages: buffer,
    has_audio: hasAudio,
    has_image: hasImage,
    has_cart: hasCart,
    media_url: mediaUrl,
    transcription: null,
    visual_description: null
  }
}];

// @ts-nocheck
// Prepara parâmetros para download de áudio via Evolution
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const fullPayload = norm.full_payload || {};
const data = fullPayload.data || fullPayload;
const key = data.key || {};

// Tenta extrair URL do media direto do payload
const message = data.message || {};
const audioMsg = message.audioMessage || message.pttMessage || {};
const directUrl = audioMsg.url || norm.media_url || '';

return [{
  json: {
    ...norm,
    audio_direct_url: directUrl,
    evolution_key: key,
    instance: norm.instance || '',
    needs_evolution_download: !directUrl || directUrl.includes('whatsapp.net')
  }
}];

// @ts-nocheck
// Converte base64 do Evolution para binary data do n8n
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const evolutionResp = $json;

const b64 = evolutionResp.base64 || evolutionResp.media || evolutionResp.data || '';

if (!b64 || evolutionResp.error) {
  // Evolution download failed — return flag for fallback
  return [{ json: { ...norm, audio_b64_missing: true, audio_error: evolutionResp.error || 'No base64 from Evolution' } }];
}

const ext = evolutionResp.ext || evolutionResp.mediaType?.split('/')[1] || 'ogg';
const mimeMap = { ogg: 'audio/ogg', mp4: 'audio/mp4', mp3: 'audio/mpeg', m4a: 'audio/mp4', wav: 'audio/wav', opus: 'audio/ogg' };
const mime = mimeMap[ext] || 'audio/ogg';

const buf = Buffer.from(b64, 'base64');
const binaryData = await $helpers.prepareBinaryData(buf, 'audio.' + ext, mime);

return [{
  json: { ...norm, audio_mime: mime, audio_ext: ext, audio_size: buf.length, audio_b64_missing: false },
  binary: { data: binaryData }
}];

// @ts-nocheck
// Merge transcription result. Handles success and all failure modes.
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const current = $json;

// Check if previous steps failed
if (norm.audio_b64_missing) {
  return [{ json: {
    ...norm,
    message_text: norm.message_text || '🎙️ [Áudio recebido — não foi possível transcrever]',
    transcription: null,
    audio_processed: false,
    agent_note: 'AUDIO_DOWNLOAD_FAILED'
  }}];
}

// Check OpenAI transcription result
const transcription = current.text || current.transcription || '';

if (!transcription && current.error) {
  return [{ json: {
    ...norm,
    message_text: norm.message_text || '🎙️ [Áudio recebido — transcrição indisponível]',
    transcription: null,
    audio_processed: false,
    agent_note: 'TRANSCRIPTION_FAILED'
  }}];
}

return [{ json: {
  ...norm,
  message_text: transcription || norm.message_text || '',
  transcription: transcription,
  audio_processed: true,
  agent_note: transcription ? 'AUDIO_TRANSCRIBED' : 'AUDIO_EMPTY'
}}];

// @ts-nocheck
// Extrai URL da imagem do payload Evolution
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const fullPayload = norm.full_payload || {};
const data = fullPayload.data || fullPayload;
const message = data.message || {};
const imgMsg = message.imageMessage || {};

// Use direct URL if available and not ephemeral whatsapp URL
let imageUrl = imgMsg.url || norm.media_url || '';

// If it's an ephemeral WA URL, use thumbnail base64 as data URL fallback
if (!imageUrl || imageUrl.includes('whatsapp.net') || imageUrl.includes('enc')) {
  const thumb = imgMsg.jpegThumbnail;
  if (thumb) {
    imageUrl = 'data:image/jpeg;base64,' + thumb;
  }
}

return [{
  json: {
    ...norm,
    image_url: imageUrl,
    image_caption: imgMsg.caption || norm.message_text || ''
  }
}];

// @ts-nocheck
// Merge image vision result
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const current = $json;

let visualDesc = '';
try {
  visualDesc = current.choices?.[0]?.message?.content || current.error?.message || '';
} catch (_) { visualDesc = ''; }

if (!visualDesc || current.error) {
  return [{ json: {
    ...norm,
    visual_description: null,
    image_processed: false,
    agent_note: (norm.agent_note || '') + ' IMAGE_ANALYSIS_FAILED'
  }}];
}

// Detect payment receipt
const isPaymentReceipt = /comprovante|pagamento|pix|transferencia|receipt/i.test(visualDesc);

return [{ json: {
  ...norm,
  visual_description: visualDesc,
  image_processed: true,
  is_payment_receipt: isPaymentReceipt,
  message_text: norm.message_text || ('[Imagem: ' + visualDesc.substring(0, 100) + ']'),
  agent_note: (norm.agent_note || '') + (isPaymentReceipt ? ' PAYMENT_RECEIPT' : ' IMAGE_REFERENCE')
}}];

// @ts-nocheck
const norm = $('CODE: MONTA CONTEXTO | S6').item.json || {};
const ctx = $json || {};

const customer = ctx.customer || {};
const conversation = ctx.conversation || {};
const recentMessages = Array.isArray(ctx.recent_messages) ? ctx.recent_messages : [];
const currentOrder = ctx.current_order || {};
const currentItems = Array.isArray(ctx.current_order_items) ? ctx.current_order_items : [];

const phone = norm.phone_normalized || '';
const customerName = customer.full_name || norm.push_name || 'cliente';
const isExisting = Boolean(customer.is_existing_customer || customer.id || ctx.customer_id);
const convStage = conversation.stage || 'new';
const humanLock = conversation.human_takeover || false;
const conversationId = ctx.conversation_id || conversation.id || null;
const customerId = ctx.customer_id || customer.id || null;
const catalogBase = String($vars.CATALOG_BASE_URL || 'https://flordoestudante-floricultura-web.vercel.app').replace(/\/+$/, '');

const currentOrderId = currentOrder.order_id || currentOrder.id || ctx.current_order_id || null;
const currentOrderCode = currentOrder.public_code || currentOrder.order_public_code || ctx.current_order_public_code || null;

const historyText = recentMessages.slice(-8).map(m => {
  const who = m.sender_type === 'agent' ? '🤖 Agente' : '👤 Cliente';
  return `${who}: ${(m.body || '').substring(0, 200)}`;
}).join('\n');

let orderContext = '';
if (currentOrderId) {
  orderContext = `Pedido atual: ${currentOrderCode || currentOrderId} (${currentOrder.status || 'draft'})\n`;
  orderContext += `  Total: R$ ${currentOrder.total_amount || currentOrder.current_order_total_amount || '?'}\n`;
  orderContext += `  Entrega: ${currentOrder.fulfillment_type || '?'}\n`;
  if (currentItems.length > 0) {
    orderContext += `  Itens: ${currentItems.map(i => `${i.product_name || i.name || i.item_name || 'item'} x${i.quantity || 1}`).join(', ')}\n`;
  }
}

let enrichedInput = norm.message_text || '';
if (norm.transcription) enrichedInput = `[Áudio transcrito]: ${norm.transcription}`;
if (norm.visual_description) enrichedInput += (enrichedInput ? '\n' : '') + `[Imagem analisada]: ${norm.visual_description}`;
if (String(norm.agent_note || '').includes('PAYMENT_RECEIPT')) enrichedInput += '\n[SISTEMA: Cliente enviou o que parece ser comprovante de pagamento]';

const SYSTEM_PROMPT = `Você é Ana, atendente virtual da Flor do Estudante 🌸 — floricultura especializada em flores, arranjos, buquês, cestas e presentes.

DATA DE HOJE: ${new Date().toLocaleDateString('pt-BR')} — período de campanha do Dia das Mães 💐

REGRAS COMERCIAIS:
1. Priorize SEMPRE o Dia das Mães. Se o cliente não especificar ocasião, pergunte.
2. Finalize vendas de forma autônoma — não transfira para humano apenas para fechar pedido/pagamento.
3. NUNCA invente produtos ou preços. Use apenas dados do catálogo fornecido pelo workflow.
4. Não bloqueie por disponibilidade de estoque — diga "posso montar esse pedido para você".
5. Faça UMA pergunta por resposta. Seja objetivo e caloroso.
6. Quando sugerir produto com slug, inclua o link: ${catalogBase}/produto/{slug}
7. Para pagamento: aceite PIX, cartão ou pagamento na entrega/retirada conforme disponível.
8. Se o cliente informar preferência clara como “flores do campo”, “rosas”, “girassol”, “cesta”, “buquê” ou orçamento, use action=search_catalog imediatamente.

REGRA DE ESCOLHA / COMPRA:
Se o cliente disser algo como "vou querer", "quero esse", "pode ser esse", "vou levar", "fecha esse", "quero a cesta", "quero o buquê", "sim, esse mesmo", "pode montar" ou "pode fechar" e houver produto claro na mensagem ou no histórico recente, a action correta é create_order_draft, não search_catalog.

Se ainda precisar localizar o item no catálogo para obter item_id/preço, use search_catalog apenas como etapa técnica, mas a próxima ação do workflow deve criar o pedido rascunho automaticamente quando encontrar correspondência forte.

Nunca responda novamente com lista de opções quando o cliente já escolheu uma opção clara.

ACTIONS DISPONÍVEIS:
- ask_info
- search_catalog
- create_order_draft
- update_order_draft
- prepare_checkout
- parse_whatsapp_cart
- handoff_human

STAGES PERMITIDOS:
identificando_necessidade, coletando_ocasiao, coletando_preferencia, coletando_orcamento, consultando_catalogo, buscando_opcoes, apresentando_opcoes, pedido_em_montagem, confirmando_pedido, coletando_entrega_ou_retirada, coletando_destinatario, coletando_mensagem_cartao, finalizando_pagamento, aguardando_pagamento, handoff, erro.

Quando action=search_catalog:
- agent_reply deve ser uma frase curta de transição, não uma pergunta.
- Exemplo: "Perfeito, vou separar algumas opções nesse estilo para você 🌸"
- A resposta final com produtos será montada após a busca no catálogo.

FLUXO SUGERIDO:
1. Entender ocasião/preferência/orçamento → buscar catálogo.
2. Sugerir 2-3 opções com link e preço.
3. Confirmar escolha → criar/atualizar pedido.
4. Confirmar entrega/retirada, destinatário, endereço e mensagem no cartão.
5. Gerar checkout → enviar link de pagamento.

FORMATO DE RESPOSTA — SEMPRE JSON VÁLIDO:
{
  "action": "search_catalog",
  "agent_reply": "Texto da resposta para o cliente",
  "agent_stage": "identificando_necessidade",
  "search_query": "",
  "occasion_filter": "dia_das_maes",
  "order_id": "",
  "order_data": {
    "fulfillment_type": "delivery | pickup",
    "recipient_name": "",
    "gift_message": "",
    "desired_date": "",
    "add_items": []
  },
  "checkout_data": {
    "payment_method": "pix | mercado_pago | pay_on_delivery | pay_on_pickup"
  }
}`;

const USER_CONTEXT = `CONTEXTO DO ATENDIMENTO:
Cliente: ${customerName} | Telefone: ${phone} | ${isExisting ? 'Cliente cadastrado' : 'Novo cliente'}
Estágio conversa: ${convStage}
${orderContext}
Histórico recente:\n${historyText || '(primeira mensagem)'}

MENSAGEM ATUAL DO CLIENTE:
${enrichedInput || '(sem texto)'}`;

return [{
  json: {
    ...norm,
    system_prompt: SYSTEM_PROMPT,
    user_context: USER_CONTEXT,
    conversation_id: conversationId,
    customer_id: customerId,
    ctx_stage: convStage,
    current_order_id: currentOrderId,
    current_order_public_code: currentOrderCode,
    transcription: norm.transcription || null,
    visual_description: norm.visual_description || null,
    human_lock: humanLock
  }
}];

// @ts-nocheck
const norm = $('CODE: PREPARA PROMPT | S6').item.json || {};
const llmResp = $json || {};

const VALID_ACTIONS = ['ask_info','search_catalog','create_order_draft','update_order_draft','prepare_checkout','parse_whatsapp_cart','handoff_human'];
const VALID_STAGES = ['new','smalltalk','identificando_necessidade','coletando_ocasiao','coletando_preferencia','coletando_orcamento','consultando_catalogo','buscando_opcoes','apresentando_opcoes','pedido_em_montagem','confirmando_pedido','coletando_entrega_ou_retirada','coletando_destinatario','coletando_mensagem_cartao','finalizando_pagamento','aguardando_pagamento','aguardando_confirmacao_humana','handoff','human_takeover','finalizado','erro'];

let parsed = null;
let rawContent = '';

try {
  rawContent = llmResp.choices?.[0]?.message?.content || '{}';
  try { parsed = JSON.parse(rawContent); } catch (_) {}
  if (!parsed) {
    const m = rawContent.match(/```(?:json)?\s*([\s\S]+?)```/);
    if (m) { try { parsed = JSON.parse(m[1]); } catch (_) {} }
  }
  if (!parsed) {
    const m2 = rawContent.match(/\{[\s\S]+\}/);
    if (m2) { try { parsed = JSON.parse(m2[0]); } catch (_) {} }
  }
} catch (e) {
  parsed = null;
}

if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      ...norm,
      agent_action: 'ask_info',
      agent_reply: 'Desculpe, tive um pequeno problema. Pode repetir sua mensagem? 🌸',
      agent_stage: norm.ctx_stage || 'identificando_necessidade',
      parse_error: true,
      raw_content: String(rawContent || '').substring(0, 500)
    }
  }];
}

const action = VALID_ACTIONS.includes(parsed.action) ? parsed.action : 'ask_info';
const stage = VALID_STAGES.includes(parsed.agent_stage) ? parsed.agent_stage : (norm.ctx_stage || 'identificando_necessidade');
const reply = (parsed.agent_reply || '').toString().trim();

if (!reply && action === 'ask_info') {
  return [{
    json: {
      ...norm,
      agent_action: 'ask_info',
      agent_reply: 'Olá! 🌸 Como posso te ajudar hoje?',
      agent_stage: stage,
      parse_error: false
    }
  }];
}

return [{
  json: {
    ...norm,
    agent_action: action,
    agent_reply: reply || '(aguardando dados)',
    agent_stage: stage,
    search_query: parsed.search_query || '',
    occasion_filter: parsed.occasion_filter || '',
    order_id: parsed.order_id || norm.current_order_id || null,
    order_data: parsed.order_data || null,
    checkout_data: parsed.checkout_data || null,
    parse_error: false
  }
}];

// @ts-nocheck
const parsed = $json || {};
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').first().json || {};

const msg = String(norm.message_text_normalized || norm.message_text || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const stage = String(parsed.agent_stage || parsed.ctx_stage || '').toLowerCase();

const strongBuyIntent = /\b(vou querer|vou levar|pode ser|pode montar|pode fechar|fecha esse|fechar esse|esse mesmo|essa mesmo|escolho|fico com|manda esse|manda essa)\b/i.test(msg);
const weakBuyIntent = /\b(quero|queria)\b/i.test(msg);
const hasProductHint = /\b(cesta|cafe da manha|buque|rosas|girassol|arranjo)\b/i.test(msg);
const isChoosingFromOptions = ['apresentando_opcoes', 'buscando_opcoes', 'consultando_catalogo'].includes(stage);

const shouldCreateOrder = hasProductHint && (strongBuyIntent || (weakBuyIntent && isChoosingFromOptions));

let cleanQuery = msg
  .replace(/\b(sim|por favor|obrigado|obrigada|vou querer|vou levar|quero|queria|pode ser|pode montar|pode fechar|fecha esse|fechar esse|esse mesmo|essa mesmo|escolho|fico com|manda esse|manda essa)\b/gi, ' ')
  .replace(/\b(a|o|um|uma|de|da|do|para|pra)\b/gi, ' ')
  .replace(/[^\p{L}\p{N}\s]/gu, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!cleanQuery && parsed.search_query) cleanQuery = String(parsed.search_query).trim();

if (shouldCreateOrder) {
  return [{
    json: {
      ...parsed,
      agent_action: 'search_catalog',
      agent_stage: 'pedido_em_montagem',
      agent_reply: 'Perfeito, vou montar esse pedido para você 🌸',
      search_query: cleanQuery || parsed.search_query || norm.message_text || '',
      occasion_filter: parsed.occasion_filter || 'dia_das_maes',
      force_create_order_after_catalog: true,
      detected_buy_intent: true
    }
  }];
}

return [{ json: { ...parsed, force_create_order_after_catalog: false, detected_buy_intent: false } }];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const inputItems = $input.all();
const catalogBase = String($vars.CATALOG_BASE_URL || 'https://flordoestudante-floricultura-web.vercel.app').replace(/\/+$/, '');

let products = [];
for (const item of inputItems) {
  const d = item.json;
  if (!d || d.error) continue;
  if (Array.isArray(d)) { products.push(...d); continue; }
  if (Array.isArray(d.items)) { products.push(...d.items); continue; }
  if (Array.isArray(d.products)) { products.push(...d.products); continue; }
  if (Array.isArray(d.catalog_items)) { products.push(...d.catalog_items); continue; }
  if (d.name || d.slug || d.item_id || d.id) products.push(d);
}

const seen = new Set();
products = products.filter((p) => {
  const key = String(p.item_id || p.id || p.slug || p.name || '');
  if (!key || seen.has(key)) return false;
  seen.add(key);
  return true;
});

products.sort((a, b) => {
  const scoreA = Number(a.match_score || 0);
  const scoreB = Number(b.match_score || 0);
  if (scoreB !== scoreA) return scoreB - scoreA;
  const imgA = a.cover_image_url ? 1 : 0;
  const imgB = b.cover_image_url ? 1 : 0;
  if (imgB !== imgA) return imgB - imgA;
  return Number(a.price || 999999) - Number(b.price || 999999);
});

const topProducts = products.slice(0, 3);
const sourceText = String($('NORMALIZA PAYLOAD WHATSAPP | S6').first().json.message_text_normalized || $('NORMALIZA PAYLOAD WHATSAPP | S6').first().json.message_text || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

function normalizeText(value) {
  return String(value || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

function productMatchesMessage(product) {
  const name = normalizeText(product.name);
  const slug = normalizeText(product.slug).replace(/-/g, ' ');
  if (!name && !slug) return false;
  return sourceText.includes(name) || sourceText.includes(slug) || (name.includes('cesta') && sourceText.includes('cesta')) || (name.includes('cafe') && sourceText.includes('cafe'));
}

const selectedProduct = topProducts.find(productMatchesMessage) || topProducts[0] || null;

if (agentCtx.force_create_order_after_catalog && selectedProduct) {
  const price = Number(selectedProduct.price || 0);
  return [{
    json: {
      ...agentCtx,
      agent_action: 'create_order_draft',
      agent_stage: 'pedido_em_montagem',
      selected_product: selectedProduct,
      selected_product_id: selectedProduct.item_id || selectedProduct.id,
      selected_product_name: selectedProduct.name,
      catalog_results: [selectedProduct],
      all_catalog_results: products,
      has_catalog_images: Boolean(selectedProduct.cover_image_url),
      first_image_product: selectedProduct.cover_image_url ? selectedProduct : null,
      order_data: {
        occasion: agentCtx.occasion_filter || 'dia_das_maes',
        source: 'whatsapp_agent',
        items: [{
          item_type: selectedProduct.item_type || 'product',
          item_id: selectedProduct.item_id || selectedProduct.id,
          product_id: selectedProduct.item_type === 'product' ? (selectedProduct.item_id || selectedProduct.id) : null,
          addon_id: selectedProduct.item_type === 'addon' ? (selectedProduct.item_id || selectedProduct.id) : null,
          name: selectedProduct.name,
          slug: selectedProduct.slug,
          quantity: 1,
          unit_price: price,
          total_price: price
        }]
      },
      agent_reply: `Perfeito, vou montar o pedido da *${selectedProduct.name}* para o Dia das Mães 🌸\n\nPara continuar, você prefere *entrega* ou *retirada na loja*?`
    }
  }];
}

const imageProducts = topProducts.filter(p => p.cover_image_url);

function formatPrice(value) {
  const num = Number(value || 0);
  if (!num) return '';
  return num.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

if (topProducts.length === 0) {
  return [{
    json: {
      ...agentCtx,
      agent_action: agentCtx.agent_action || 'ask_info',
      agent_stage: agentCtx.agent_stage || 'buscando_opcoes',
      agent_reply: 'Não encontrei uma opção exata para essa busca agora, mas posso te mostrar algumas sugestões para o Dia das Mães 🌸',
      catalog_results: [],
      has_catalog_images: false,
      first_image_product: null,
      catalog_base: catalogBase,
      catalog_count: 0
    }
  }];
}

const lines = topProducts.map((p, i) => {
  const label = i === 0 ? '🌸' : i === 1 ? '💐' : '🌷';
  const price = formatPrice(p.price);
  const url = p.slug ? `${catalogBase}/produto/${p.slug}` : '';
  const description = p.short_description || p.description || '';
  return [`${label} *${p.name || 'Produto'}*${price ? ' — ' + price : ''}`, description || '', url ? `🔗 ${url}` : ''].filter(Boolean).join('\n');
});

const intro = agentCtx.agent_reply && !agentCtx.agent_reply.includes('Não encontrei') ? agentCtx.agent_reply : 'Encontrei algumas opções para o Dia das Mães 🌸';
const replyText = `${intro}\n\n${lines.join('\n\n')}\n\nGostou de alguma dessas opções?`;

return [{
  json: {
    ...agentCtx,
    agent_action: 'search_catalog',
    agent_stage: 'apresentando_opcoes',
    agent_reply: replyText,
    catalog_results: topProducts,
    all_catalog_results: products,
    has_catalog_images: imageProducts.length > 0,
    first_image_product: imageProducts[0] || null,
    catalog_base: catalogBase,
    catalog_count: products.length
  }
}];

// @ts-nocheck
const ctx = $json || {};

function money(value) {
  return Number(value || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

const selected = ctx.selected_product || (Array.isArray(ctx.catalog_results) ? ctx.catalog_results[0] : null) || ctx.first_image_product || null;

if (!selected) {
  return [{
    json: {
      ...ctx,
      agent_action: 'ask_info',
      agent_stage: 'buscando_opcoes',
      agent_reply: 'Perfeito! Só preciso confirmar qual produto você escolheu para montar o pedido 🌸',
      order_data: ctx.order_data || {},
      suggested_addons: [],
      can_create_order: false
    }
  }];
}

const allResults = Array.isArray(ctx.all_catalog_results) ? ctx.all_catalog_results : Array.isArray(ctx.catalog_results) ? ctx.catalog_results : [];

const suggestedAddons = allResults
  .filter((item) => {
    if (!item || item.item_type !== 'addon' || !item.name) return false;
    const name = String(item.name).toLowerCase();
    return name.includes('cart') || name.includes('chocolate') || name.includes('vela') || name.includes('pelúcia') || name.includes('pelucia') || name.includes('urso') || name.includes('balão') || name.includes('balao');
  })
  .slice(0, 3)
  .map((item) => ({
    item_type: item.item_type || 'addon',
    item_id: item.item_id || item.id,
    addon_id: item.item_id || item.id,
    name: item.name,
    slug: item.slug,
    quantity: 1,
    unit_price: Number(item.price || 0),
    total_price: Number(item.price || 0),
    short_description: item.short_description || item.description || ''
  }));

const unitPrice = Number(selected.price || 0);

const primaryItem = {
  item_type: selected.item_type || 'product',
  item_id: selected.item_id || selected.id,
  product_id: selected.item_type === 'product' ? (selected.item_id || selected.id) : null,
  addon_id: selected.item_type === 'addon' ? (selected.item_id || selected.id) : null,
  name: selected.name,
  slug: selected.slug,
  quantity: 1,
  unit_price: unitPrice,
  total_price: unitPrice,
  short_description: selected.short_description || selected.description || ''
};

const orderData = {
  ...(ctx.order_data || {}),
  occasion: ctx.order_data?.occasion || ctx.occasion_filter || 'dia_das_maes',
  is_gift: ctx.order_data?.is_gift ?? true,
  fulfillment_type: ctx.order_data?.fulfillment_type || null,
  items: [primaryItem],
  suggested_addons: suggestedAddons,
  selected_product: {
    id: selected.id,
    item_id: selected.item_id || selected.id,
    item_type: selected.item_type,
    name: selected.name,
    slug: selected.slug,
    price: unitPrice,
    cover_image_url: selected.cover_image_url || ''
  }
};

return [{
  json: {
    ...ctx,
    agent_action: 'create_order_draft',
    agent_stage: 'pedido_em_montagem',
    selected_product: selected,
    selected_product_id: selected.item_id || selected.id,
    selected_product_name: selected.name,
    order_data: orderData,
    suggested_addons: suggestedAddons,
    can_create_order: true,
    order_summary_preview: {
      product_name: selected.name,
      product_price: money(unitPrice),
      suggested_addons: suggestedAddons.map(a => ({ name: a.name, price: money(a.unit_price) }))
    }
  }
}];

// @ts-nocheck
const ctx = $('CODE: PREPARA ORDER DRAFT | S6').first().json || {};
const res = $json || {};

function money(value) {
  return Number(value || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

const selected = ctx.selected_product || ctx.order_data?.selected_product || {};
const addons = Array.isArray(ctx.suggested_addons) ? ctx.suggested_addons : [];

const orderId = res.order_id || res.id || res.order?.id || ctx.order_id || null;
const publicCode = res.public_code || res.order_public_code || res.order?.public_code || ctx.public_code || null;

let addonText = '';
if (addons.length > 0) {
  const addonList = addons.slice(0, 3).map((a) => `*${a.name}* (${money(a.unit_price)})`).join(', ');
  addonText = `\n\nSe quiser deixar o presente ainda mais especial, também posso incluir ${addonList}.`;
}

const productName = selected.name || ctx.selected_product_name || 'esse produto';
const productPrice = selected.price ? ` — ${money(selected.price)}` : '';

const reply = [
  `Perfeito! Já montei o pedido da *${productName}*${productPrice} para o Dia das Mães 🌸`,
  addonText,
  `\n\nAgora me diga: você prefere *entrega* ou *retirada na loja*?`
].join('');

return [{
  json: {
    ...ctx,
    ...res,
    order_id: orderId,
    public_code: publicCode,
    agent_action: 'update_order_draft',
    agent_stage: 'coletando_entrega_ou_retirada',
    agent_reply: reply,
    order_data: { ...(ctx.order_data || {}), order_id: orderId, public_code: publicCode },
    suggested_addons: addons,
    selected_product: selected
  }
}];

// @ts-nocheck
const src = $('CODE: FORMATA CATÁLOGO | S6').item.json || {};
const imageWasAttempted = Boolean(src.has_catalog_images && src.first_image_product?.cover_image_url);

return [{
  json: {
    ...src,
    image_attempted: imageWasAttempted,
    image_sent: imageWasAttempted
  }
}];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};

return [{
  json: {
    ...agentCtx,
    ...result,
    order_id: result.order_id || agentCtx.order_id || agentCtx.order_data?.order_id || null,
    public_code: result.public_code || agentCtx.public_code || agentCtx.order_data?.public_code || null,
    agent_reply: result.ok === false
      ? (agentCtx.agent_reply || 'Certo 🌸') + '\n_(houve um problema ao atualizar o pedido, vamos continuar)_'
      : (agentCtx.agent_reply || 'Perfeito, atualizei o pedido por aqui 🌸'),
    agent_action: 'update_order_draft',
    agent_stage: agentCtx.agent_stage || 'pedido_em_montagem'
  }
}];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};
const matchedCount = result.items?.filter(i => i.matched)?.length || 0;
const totalCount = result.item_count || result.items?.length || 0;

return [{
  json: {
    ...agentCtx,
    ...result,
    cart_batch_id: result.batch_id || null,
    cart_matched: matchedCount,
    cart_total: totalCount,
    agent_action: 'parse_whatsapp_cart',
    agent_stage: 'confirmando_pedido',
    agent_reply: matchedCount > 0
      ? (agentCtx.agent_reply || 'Identifiquei os itens do seu carrinho. Posso confirmar o pedido?')
      : (agentCtx.agent_reply || 'Identifiquei os itens do seu carrinho.') + '\n\nPosso confirmar o pedido?'
  }
}];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};

if (!result.ok) {
  return [{
    json: {
      ...agentCtx,
      ...result,
      agent_reply: (agentCtx.agent_reply || '') + '\n\n_(Houve um erro ao gerar o link de pagamento. Entre em contato conosco.)_',
      checkout_ok: false,
      agent_stage: 'erro'
    }
  }];
}

const checkoutUrl = result.checkout_url || '';
const summary = result.order_summary_text || '';

const replyLines = [
  agentCtx.agent_reply || summary,
  '',
  summary !== agentCtx.agent_reply ? summary : '',
  '',
  checkoutUrl ? `💳 *Link de pagamento:*\n${checkoutUrl}` : '',
  '',
  'Após o pagamento, seu pedido será confirmado. Qualquer dúvida, é só chamar! 🌸'
].filter(l => l !== null && l !== undefined && l !== '');

return [{
  json: {
    ...agentCtx,
    ...result,
    agent_reply: replyLines.join('\n').replace(/\n{3,}/g, '\n\n').trim(),
    checkout_url: checkoutUrl,
    checkout_ok: true,
    agent_action: 'prepare_checkout',
    agent_stage: 'finalizando_pagamento',
    public_code: result.public_code || agentCtx.public_code || null
  }
}];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};

return [{
  json: {
    ...agentCtx,
    ...result,
    human_lock_set: true,
    agent_action: 'handoff_human',
    agent_stage: 'handoff',
    agent_reply: agentCtx.agent_reply || 'Certo, vou chamar uma pessoa da equipe para te ajudar por aqui 🌸'
  }
}];

// @ts-nocheck
const src = $json || {};
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').first().json || {};
const prompt = $('CODE: PREPARA PROMPT | S6').first().json || {};

const fallbackReply = 'Olá! 🌸 Tive um probleminha técnico por aqui. Pode repetir sua mensagem?';

return [{
  json: {
    ...src,
    phone_normalized: src.phone_normalized || norm.phone_normalized || '',
    push_name: src.push_name || norm.push_name || '',
    conversation_id: src.conversation_id || prompt.conversation_id || null,
    customer_id: src.customer_id || prompt.customer_id || null,
    agent_reply: String(src.agent_reply || fallbackReply).trim(),
    agent_action: src.agent_action || 'ask_info',
    agent_stage: src.agent_stage || src.ctx_stage || prompt.ctx_stage || 'identificando_necessidade',
    order_id: src.order_id || src.created_order_id || src.order_data?.order_id || prompt.current_order_id || null,
    public_code: src.public_code || src.created_order_code || src.order_data?.public_code || prompt.current_order_public_code || null,
    checkout_url: src.checkout_url || null,
    catalog_results: src.catalog_results || [],
    selected_product: src.selected_product || null,
    suggested_addons: src.suggested_addons || [],
    technical_notes: src.technical_notes || []
  }
}];

// @ts-nocheck
const finalOut = $('CODE: NORMALIZA SAÍDA FINAL | S6').item.json || {};
const phoneNorm = $('NORMALIZA PAYLOAD WHATSAPP | S6').item.json.phone_normalized;

return [{
  json: {
    agent_reply: finalOut.agent_reply || 'Olá! 🌸 Tive um probleminha técnico. Pode repetir sua mensagem?',
    phone_normalized: finalOut.phone_normalized || phoneNorm
  }
}];

